Modify.SQL:
					SELECT 'EXISTS' FROM TASK_COUNTS TC
				  	WHERE TC.TASK_NUMBER  = ${TC.TASK_NUMBER}
				   	AND TC.TASK_DATE  = TO_DATE(${TC.TASK_DATE}, 'DD-MM-RR')
				   	AND TC.AGE_CATEGORY  = ${TC.AGE_CATEGORY} 
				   	AND TC.ADMIN_COURT_CODE  = ${TC.ADMIN_COURT_CODE}
				   	AND	TC.CREATING_COURT = ${TC.CREATING_COURT}
                   	AND TC.CREATING_SECTION = ${TC.CREATING_SECTION}

				 UPDATE 	TASK_COUNTS TC 
				 SET TC.TASK_COUNT  =
				 	 (SELECT TC.TASK_COUNT+${TC.TASK_COUNT} 
				 	  FROM	TASK_COUNTS TC  WHERE  
				  			TC.TASK_NUMBER  = ${TC.TASK_NUMBER}
				  			AND TC.TASK_DATE  = TO_DATE(${TC.TASK_DATE}, 'DD-MM-RR') 
				  			AND TC.AGE_CATEGORY  = ${TC.AGE_CATEGORY}
				  			AND TC.ADMIN_COURT_CODE  = ${TC.ADMIN_COURT_CODE}
				   			AND	TC.CREATING_COURT = ${TC.CREATING_COURT}
                   			AND TC.CREATING_SECTION = ${TC.CREATING_SECTION})  
				  WHERE  	TC.TASK_NUMBER  = ${TC.TASK_NUMBER}
				   AND 		TC.TASK_DATE  = TO_DATE(${TC.TASK_DATE}, 'DD-MM-RR')
				   AND 		TC.AGE_CATEGORY  = ${TC.AGE_CATEGORY} 
				   AND 		TC.ADMIN_COURT_CODE  = ${TC.ADMIN_COURT_CODE}
				   AND		TC.CREATING_COURT = ${TC.CREATING_COURT}
                   AND 		TC.CREATING_SECTION = ${TC.CREATING_SECTION}
				   AND 		TC.TASK_COUNT+${TC.TASK_COUNT}  >= 0
